text:
{
  "formal_minutes": {
    "decisions": [
      {
        "id": "D1",
        "type": "확정 의사결정",
        "summary": "최종 공개 릴리스 대상은 Smoke 테스트 통과 시 금요일 15:00 KST로 한다."
      },
      {
        "id": "D2",
        "type": "확정 의사결정",
        "summary": "패키지명 불일치가 발생하더라도 임시로 `smoke-theme-pack.mjs`를 무시 처리하지 않는다. 우선 패키지 설정을 확인하고, 계약/명세 자체가 잘못된 경우에만 스크립트를 재검토한다."
      },
      {
        "id": "D3",
        "type": "확정 액션",
        "summary": "Minjun이 금요일 10:00 KST까지 Smoke 테스트를 재실행하고 결과 공유.",
        "source": "확정 액션 아이템"
      },
      {
        "id": "D4",
        "type": "확정 액션",
        "summary": "Doyun이 금요일 12:00 KST까지 action_items.md에 Failure Triage Note 작성.",
        "source": "확정 액션 아이템"
      }
    ],
    "non_decisions": [
      {
        "id": "ND1",
        "type": "미확정 항목",
        "summary": "금요일 15:00 릴리스 조건(최종 승인자, 최종 배포 허가) 및 최종 승인 책임자는 미확정이다."
      },
      {
        "id": "ND2",
        "type": "미확정 항목",
        "summary": "릴리스 노트에 내부 스프린트형 마일스톤인 수요일 목표(Stretch Goal)를 노출할지 여부는 결정되지 않았다."
      },
      {
        "id": "ND3",
        "type": "미확정 항목",
        "summary": "README 설치 가이드 검토의 최종 소유자와 확정 일정은 지정되지 않았다."
      }
    ],
    "rejections": [
      {
        "id": "R1",
        "type": "거부 제안",
        "summary": "수요일 공개 릴리스 제안은 Smoke 테스트 사전 통과 요건 때문에 거부됨.",
        "outcome": "수요일은 내부 스프린트 목표로만 유지"
      },
      {
        "id": "R2",
        "type": "거부 제안",
        "summary": "Hara의 `smoke-theme-pack.mjs`에서 packageName mismatch 무시 처리 제안은 거부됨."
      }
    ],
    "stretch_goals": [
      {
        "id": "SG1",
        "type": "내부 Stretch Goal",
        "summary": "수요일 릴리스 달성 시도는 내부 목표로 유지하되, 확정 릴리스일은 아니다."
      }
    ],
    "risks": [
      {
        "id": "RK1",
        "type": "릴리스 리스크",
        "summary": "잘못된 tarball 경로로 인해 패키지 산출물 식별/검증이 실패해 릴리스가 지연될 수 있음."
      },
      {
        "id": "RK2",
        "type": "문서 리스크",
        "summary": "README 설치 단계가 오래된 상태면 릴리스 노트가 사용자에게 오도 가능성."
      }
    ],
    "open_questions": [
      {
        "id": "Q1",
        "type": "열린 질문",
        "summary": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "id": "Q2",
        "type": "열린 질문",
        "summary": "릴리스 노트에 내부 수요일 stretch goal(내부 일정성 목표)를 공개할지 여부."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "Smoke 테스트 재실행 및 결과 공유",
      "due": "금요일 10:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Doyun",
      "task": "Failure triage note를 action_items.md에 작성",
      "due": "금요일 12:00 KST",
      "status": "확정",
      "source_certainty": "high"
    },
    {
      "owner": "Hara",
      "task": "생성된 tarball 경로 확인 (Minjun Smoke 결과 게시 후)",
      "due": "미정",
      "status": "진행 예정",
      "source_certainty": "medium"
    },
    {
      "owner": "미정",
      "task": "README 설치 단계 최신성 검토 완료",
      "due": "목표: 목요일 가능 시",
      "status": "보류(소유자 미할당)",
      "source_certainty": "high"
    }
  ],
  "followup_note": {
    "to_check_next": [
      "README 설치 단계 검토 담당자 할당 및 실제 검토 완료 여부 확인",
      "Hara의 tarball 경로 확인 결과 및 실패 시 조치(패키지 경로 정합성, 산출물 저장 위치) 확인",
      "Smoke 테스트 통과 여부와 실패 항목(있을 경우) 재현/근본원인 정리",
      "최종 릴리스 승인권자 및 승인 절차 확정",
      "릴리스 노트에 수요일 Stretch Goal 반영 여부 최종 결정 및 커뮤니케이션 기준 합의"
    ],
    "do_not_invent": [
      "고객명/외부 파트너 정보",
      "예산 수치",
      "보안 사고 이슈",
      "운영 장애(incident) 또는 복구 시나리오",
      "법무 승인 필수 조건",
      "미확정 소유자·마감일·승인권자(근거 없는 특정인 지정)"
    ]
  },
  "non_invention_rules": [
    "모든 사실은 주어진 공개 시뮬레이션 미팅 원문에서만 추론 없이 직접 반영한다.",
    "명시되지 않은 소유자, 기한, 고객/파트너, 예산, 보안/법무/아웃리지 관련 사실은 추가하지 않는다.",
    "제출 형식은 한국어 JSON으로 유지하고 키 형식을 임의 변경하지 않는다.",
    "이미지, 표기준, 근거 문서 파일 경로 등 외부 참조는 생성하지 않는다."
  ]
}
